INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('optometrist-moex-02234', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關角膜的敘述，下列何者最不適當？', '["一般的角膜K值平均值是43.00 D到45.00 D，所以如果K值小於40.00 D或者大於48.00 D很少見， 應該重新量過比較妥當", "針對同一個眼睛，以不同的角膜弧度計（keratometer）所測得到的角膜屈折力均相同", "針對角膜弧度的度數太高，超過儀器可以測量的範圍者，有的可以加上+1.25 D或者更高度數的球面鏡 片，配合對照表可以計算得到角膜弧度", "角膜弧度在隱形眼鏡的驗配，追蹤角膜弧度的變化，或甚至在診斷圓錐角膜都可以提供助益"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02235', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關視網膜檢影鏡（retinoscopy）檢查的敘述，下列何者最不適當？', '["斷裂現象（break phenomenon）是指散光的病人在瞳孔內的反光有可能與視網膜鏡的光線（streak）不 連續", "斷裂現象可以幫助我們去找散光的軸度", "偏移現象（skew phenomenon）可以幫助我們去找散光的軸度", "偏移現象是指在不同的經緯度（meridian）檢查散光的病人時，其反光的厚度會不一樣"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02236', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '如果檢影是使用+1.50 D透鏡，在垂直方向中和點為66.7 cm，水平方向的中和點為40 cm，估計屈光不正為：', '["-1.50DS/-1.00DC×090", "-2.50DS/-1.50DC×090", "plano/-1.00DC×090", "plano/+2.00DC×180"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02237', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '視網膜檢影鏡檢查距離病患眼睛66 cm投射平行光，使用鏡片-3.50 D在垂直方向呈現中和，-2.00 D在180 度呈現水平方向，病患此眼屈光狀態最可能為何？', '["-5.50DS/-3.50DC×180", "-1.50DS/-1.50DC×090", "-3.50DS/-1.50DC×180", "-3.50DS/-1.50DC×090"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02238', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '有關角膜地圖儀（corneal topography）之敘述，下列何者錯誤？', '["可精確描繪出所有軸度上的角膜表面形狀", "所使用的視標為同心圓環組，又稱做普雷希多圓盤（Placido disc）", "其測得之散光度（astigmatic power）與自動驗光儀相同", "其測得之模擬K值（simulate keratometry, Sim K）與角膜弧度儀測量結果相似"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02239', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '使用交叉圓柱鏡驗證散光度數，以+/-0.25 D圓柱鏡逐次修正散光。如原驗光度數為+2.00DS/+1.25DC×080， 根據此度數調整，綜合驗光儀的鏡片度數，翻轉交叉圓柱鏡，發現白點位置在80度時視標比較清楚。經 過修改散光度數後，再次翻轉交叉圓柱鏡，發現白點位置在80度時，視標仍然比較清楚，則驗光度數宜 修正為下列何者？', '["+1.75DS/+1.75DC×080", "+2.00DS/+1.75DC×080", "+2.00DS/+0.75DC×080", "+2.25DS/+0.75DC×080"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02240', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '進行傑克森交叉圓柱鏡（Jackson cross-cylinder, JCC）檢測之前，綜合驗光儀裡的度數為-2.00DS/-2.00DC×080， 而檢查過程中受檢者散光軸度沒有改變，但散光度數降至-1.00 DC。若檢測操作正確，此受檢者在測量完 傑克森交叉圓柱鏡時，綜合驗光儀裡的度數應該是下列何者？', '["-1.00DS/-1.00DC×080", "-1.50DS/-1.00DC×080", "-2.00DS/-1.00DC×080", "-2.50DS/-1.00DC×080"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02241', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '關於紅綠試驗的敘述，下列何者正確？', '["如果紅色視標比綠色視標清楚，此表示焦點落在視網膜之前，必須先加+0.25 D修正", "如果綠色視標比紅色視標清楚，此表示焦點落在視網膜之前，必須先加-0.25 D修正", "如果紅色視標比綠色視標清楚，此表示焦點落在視網膜之後，必須先加+0.25 D修正", "如果紅色視標比綠色視標清楚，此表示焦點落在視網膜之前，必須先加-0.25 D修正"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
  ('optometrist-moex-02242', 'optometrist', 'optometrist-moex-108-c33a0f9f', 'sub-optometrist-03', NULL, 'single_choice', '下列何者適合用在遠方球面度數的測量？', '["紅綠試驗", "交替遮蓋雙眼比較", "偏光鏡測量", "稜鏡測量"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:51+00:00", "source_pdf_sha1": "276817daacd1", "answer_pdf_sha1": "5f97e486c625", "source_family": "moex-gov-tw", "moex": {"exam_code": "108060", "c": "401", "s": "0803", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "視光學", "year": "108", "exam_name": "108年專技人員高等考試大地工程技師考試分階段考試、驗船師、引水人、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optometrist", "db_exam_id": "optometrist"}'::jsonb, NULL),
